#include <bits/stdc++.h>
using namespace std;
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--) {
        int n; cin>>n;
        unordered_set<long long> seen;
        seen.reserve(n*2);
        for(int i=0;i<n;++i){
            long long x; cin>>x;
            seen.insert(x);
        }
        cout<<2<<"\n"<<seen.size()<<"\n";
    }
    return 0;
}

